SELECT
ID

INVOICE_REQUEST_ID

SERIAL_NUMBER

NATURE_LINES

ITEM

SPECIFICATION

MEASUREMENT_DIMENSION

QUANTITY

PRICE

AMOUNT

TAX_SCHEME

TAX_AMOUNT

TAX_MARK

PRODUCT_CODE

SELF_PRODUCT_CODE

ZERO_TAX_SCHEME_MARK

CREATE_BY

CREATE_BY_NAME

CREATE_TIME

UPDATE_BY

UPDATE_BY_NAME

UPDATE_TIME

FROM
T_SD_INVOICE_REQUEST_ITEM


        and ID = #{id}


        and INVOICE_REQUEST_ID = #{invoiceRequestId}


        and SERIAL_NUMBER = #{serialNumber}


        and NATURE_LINES = #{natureLines}


        and ITEM = #{item}


        and SPECIFICATION = #{specification}


        and MEASUREMENT_DIMENSION = #{measurementDimension}


        and QUANTITY = #{quantity}


        and PRICE = #{price}


        and AMOUNT = #{amount}


        and TAX_SCHEME = #{taxScheme}


        and TAX_AMOUNT = #{taxAmount}


        and TAX_MARK = #{taxMark}


        and PRODUCT_CODE = #{productCode}


        and SELF_PRODUCT_CODE = #{selfProductCode}


        and ZERO_TAX_SCHEME_MARK = #{zeroTaxSchemeMark}
